        "// ps1_vertex.glsl — Vertex wobble via integer position snapping
varying vec2 vUv;
varying vec3 vWorldPos;
uniform float uTime;
uniform float uWobbleIntensity; // 0.5–2.0

void main() {
    vec4 worldPos = modelMatrix * vec4(position, 1.0);
    // PS1-style integer vertex snapping (low-precision emulation)
    float snapRes = 64.0; // simulate 2^6 integer precision
    worldPos.xyz = floor(worldPos.xyz * snapRes) / snapRes;
    // Subtle sinusoidal wobble on Y axis
    worldPos.y += sin(worldPos.x * 3.0 + uTime * 0.5) * uWobbleIntensity * 0.02;
    vWorldPos = worldPos.xyz;
    vec4 mvPosition = modelViewMatrix * vec4(position, 1.0);
    gl_Position = projectionMatrix * mvPosition;
    vUv = uv;
}",

        "// ps1_fragment.glsl — Color quantization + shadow tint
varying vec2 vUv;
varying vec3 vWorldPos;
uniform sampler2D uTexture;
uniform vec3 uShadowTint; // #003344 = (0.0, 0.2, 0.267)
uniform float uColorDepth; // 16.0 or 32.0 for band count per channel
uniform vec3 uFogColor;
uniform float uFogNear;
uniform float uFogFar;

void main() {
    vec4 texColor = texture2D(uTexture, vUv);
    // PS1 15-bit color quantization (5 bits per channel = 32 bands)
    float bands = uColorDepth;
    vec3 quantized = floor(texColor.rgb * bands) / (bands - 1.0);
    // Apply shadow tint #003344 to darker areas
    float luminance = dot(quantized, vec3(0.299, 0.587, 0.114));
    vec3 shadowTinted = mix(quantized, uShadowTint, (1.0 - luminance) * 0.6);
    // Distance fog
    float depth = gl_FragCoord.z / gl_FragCoord.w;
    float fogFactor = smoothstep(uFogNear, uFogFar, depth);
    vec3 finalColor = mix(shadowTinted, uFogColor, fogFactor);
    // Dithering pattern overlay (PS1-style ordered dither)
    float dither = mod(gl_FragCoord.x + gl_FragCoord.y * 2.0, 4.0) / 4.0;
    finalColor += (dither - 0.5) * 0.03;
    gl_FragColor = vec4(finalColor, 1.0);
}",

