        "# llm_client.py — Streaming LLM client with AsyncGenerator
from typing import AsyncGenerator
import httpx

MODEL = "deepseek-chat"
API_URL = "https://api.deepseek.com/v1/messages"

async def call_llm_stream(prompt: str, history: list) -> AsyncGenerator[str, None]:
    """Stream LLM response token-by-token using stream=True.
    Compatible with Anthropic Messages API via DeepSeek proxy.
    """
    messages = build_messages(prompt, history)
    async with httpx.AsyncClient(timeout=60.0) as client:
        async with client.stream(
            "POST",
            API_URL,
            json={
                "model": MODEL,
                "messages": messages,
                "max_tokens": 4096,
                "stream": True,
                "temperature": 0.8
            },
            headers={"Authorization": f"Bearer {API_KEY}"}
        ) as response:
            response.raise_for_status()
            async for line in response.aiter_lines():
                if line.startswith("data: "):
                    data = line[6:]
                    if data == "[DONE]":
                        return
                    import json
                    chunk = json.loads(data)
                    delta = chunk.get("choices", [{}])[0].get("delta", {})
                    content = delta.get("content", "")
                    if content:
                        yield content


def build_messages(prompt: str, history: list) -> list:
    msgs = []
    for entry in history[-20:]:  # keep last 20 turns
        msgs.append({"role": entry["role"], "content": entry["content"]})
    msgs.append({"role": "user", "content": prompt})
    return msgs",

