      "summary": "FastAPI WebSocket endpoint (/ws/game) with Python AsyncGenerator[str, None] for streaming LLM tokens to browser (typewriter effect). Pattern: WebSocket accepts, receives player action, invokes call_llm_stream() with stream=True, yields each chunk.delta.text via await ws.send_json(). Parallel HTTP POST /api/game/action for non-streaming fallback. Feasibility: PASS -- FastAPI natively supports WebSocket via Starlette; AsyncGenerator with stream=True is the idiomatic pattern.",
      "code_examples": [
        "# server.py -- FastAPI WebSocket streaming endpoint
@app.websocket("/ws/game")
async def websocket_game(ws: WebSocket):
    await ws.accept()
    session_id = None
    try:
        while True:
            data = await ws.receive_json()
            if data.get("type") == "init":
                session_id = data.get("session_id", str(uuid4()))
                await ws.send_json({"type": "init_ack", "session_id": session_id})
            elif data.get("type") == "action":
                result = await process_action(data["input"], session_id)
                await ws.send_json({"type": "stream_start"})
                async for token in call_llm_stream(result.prompt, result.history):
                    await ws.send_json({"type": "token", "text": token})
                await ws.send_json({"type": "stream_end", "viewer_count": result.viewer_count, "scene_trigger": result.scene_trigger})
    except WebSocketDisconnect:
        pass",
        "# llm_client.py -- AsyncGenerator streaming client
from typing import AsyncGenerator
import httpx

async def call_llm_stream(prompt: str, history: list) -> AsyncGenerator[str, None]:
    async with httpx.AsyncClient(timeout=60.0) as client:
        async with client.stream("POST", API_URL, json={
            "model": MODEL, "messages": build_messages(prompt, history),
            "max_tokens": 4096, "stream": True, "temperature": 0.8
        }) as response:
            async for line in response.aiter_lines():
                if line.startswith("data: "):
                    data = line[6:]
                    if data == "[DONE]":
                        return
                    content = json.loads(data).get("choices",[{}])[0].get("delta",{}).get("content","")
                    if content:
                        yield content",
